const size_t DETWS_THEME_BLOB_COUNT = 68;

const char *detws_theme_css(const char *name)
{
    if (!name)
        return nullptr;
    for (size_t i = 0; i < DETWS_THEME_BLOB_COUNT; i++)
        if (strcmp(DETWS_THEME_BLOBS[i].name, name) == 0)
            return DETWS_THEME_BLOBS[i].css;
    return nullptr;
}

